import '../lib/envelope_codec.dart';
import '../lib/message.dart';
import '../lib/varint.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  check(encodeVarint(300).join(',') == '172,2', 'multi-byte varint encoding');
  final decodedNumber = decodeVarint(<int>[0xac, 0x02]);
  check(decodedNumber.value == 300 && decodedNumber.bytesRead == 2, 'multi-byte varint decoding');

  final text = List<String>.filled(180, 'x').join();
  final messages = decodeEnvelopes(encodeEnvelope(Message('large', text)));
  check(messages.single.text == text, 'envelope consumes the full length prefix');
  print('feedback tests passed');
}
